// Minimal force-directed graph renderer used in place of a bundled
// Cytoscape. Shipping a full Cytoscape would add ~600 KB to every ARGUS
// binary; this file is ~3 KB and covers the exact rendering we need:
// coloured nodes, directed edges, tap-to-inspect.
//
// Exposes a global `cytoscape(opts)` factory with a minimal subset of the
// Cytoscape API that app.js uses:
//   .destroy()
//   .on(event, selector, handler)
//
// `style` and `layout` properties on opts are accepted for API compatibility
// but only the colour hints are honoured.
(function(global) {
  function cytoscape(opts) {
    const container = opts.container;
    const raw = opts.elements || [];
    const nodes = raw.filter(e => !e.data.source);
    const edges = raw.filter(e => e.data.source);

    container.innerHTML = '';
    const svgNS = 'http://www.w3.org/2000/svg';
    const svg = document.createElementNS(svgNS, 'svg');
    svg.setAttribute('width', '100%');
    svg.setAttribute('height', '100%');
    svg.setAttribute('viewBox', '0 0 1000 500');
    svg.style.cursor = 'grab';
    container.appendChild(svg);

    // Position nodes on concentric rings: chain nodes outside, rule
    // nodes inside. Not as pretty as a real force layout but readable
    // and deterministic.
    const chainNodes = nodes.filter(n => n.data.kind === 'chain');
    const ruleNodes = nodes.filter(n => n.data.kind !== 'chain');
    const cx = 500, cy = 250;
    chainNodes.forEach((n, i) => {
      const a = (i / Math.max(chainNodes.length, 1)) * Math.PI * 2;
      n._x = cx + Math.cos(a) * 220;
      n._y = cy + Math.sin(a) * 200;
    });
    ruleNodes.forEach((n, i) => {
      const a = (i / Math.max(ruleNodes.length, 1)) * Math.PI * 2;
      n._x = cx + Math.cos(a) * 100;
      n._y = cy + Math.sin(a) * 90;
    });
    const byId = {};
    nodes.forEach(n => byId[n.data.id] = n);

    // Edges first (so nodes render on top).
    edges.forEach(e => {
      const s = byId[e.data.source], t = byId[e.data.target];
      if (!s || !t) return;
      const ln = document.createElementNS(svgNS, 'line');
      ln.setAttribute('x1', s._x); ln.setAttribute('y1', s._y);
      ln.setAttribute('x2', t._x); ln.setAttribute('y2', t._y);
      ln.setAttribute('stroke', '#2a3158');
      ln.setAttribute('stroke-width', '1.2');
      svg.appendChild(ln);
    });

    // Nodes.
    const severityColor = (sev, kind) => {
      if (kind === 'chain') {
        if (sev === 'CRITICAL') return '#f43f5e';
        if (sev === 'HIGH') return '#fb923c';
        return '#ec4899';
      }
      return '#6366f1';
    };

    const listeners = { tap: [] };
    nodes.forEach(n => {
      const g = document.createElementNS(svgNS, 'g');
      g.setAttribute('transform', `translate(${n._x},${n._y})`);
      g.style.cursor = 'pointer';
      const isChain = n.data.kind === 'chain';
      const shape = document.createElementNS(svgNS, isChain ? 'rect' : 'circle');
      if (isChain) {
        shape.setAttribute('x', '-58'); shape.setAttribute('y', '-14');
        shape.setAttribute('width', '116'); shape.setAttribute('height', '28');
        shape.setAttribute('rx', '6');
      } else {
        shape.setAttribute('r', '14');
      }
      shape.setAttribute('fill', severityColor(n.data.severity, n.data.kind));
      shape.setAttribute('stroke', '#151b30');
      shape.setAttribute('stroke-width', '2');
      g.appendChild(shape);

      const txt = document.createElementNS(svgNS, 'text');
      txt.setAttribute('text-anchor', 'middle');
      txt.setAttribute('dominant-baseline', 'central');
      txt.setAttribute('fill', 'white');
      txt.setAttribute('font-size', isChain ? '9' : '8');
      txt.textContent = isChain ? (n.data.label.length > 18 ? n.data.label.slice(0, 18) + '…' : n.data.label) : n.data.label;
      g.appendChild(txt);

      g.addEventListener('click', () => {
        listeners.tap.forEach(h => h({ target: { data: () => n.data } }));
      });

      svg.appendChild(g);
    });

    return {
      destroy: () => { container.innerHTML = ''; },
      on: (event, selector, handler) => {
        if (event === 'tap') listeners.tap.push(typeof selector === 'function' ? selector : handler);
      },
    };
  }

  global.cytoscape = cytoscape;
})(window);
